// Installer transform: emits codex/install-agents.sh (idempotent placement of the Codex
// subagents into ~/.codex/agents — Codex plugins cannot bundle subagents, so this is the
// one out-of-band step) and codex/README.md (the two-part Codex install docs). Both are
// static, so they regenerate byte-identically and pass the freshness gate. Emitted once.
import { register } from './registry.mjs'
import { MARKETPLACE_ADD_FROM_REPO } from '../schema.mjs'

const INSTALL_SH = `#!/usr/bin/env bash
# GENERATED by scripts/gen-codex — do not edit. Installs this marketplace's Codex subagents
# into your Codex agents dir. Codex plugins cannot bundle subagents, so this is out-of-band.
# Usage: bash codex/install-agents.sh [--force]   (CODEX_HOME defaults to ~/.codex)
set -euo pipefail
here="$(cd "$(dirname "$0")" && pwd)"
dest="\${CODEX_HOME:-$HOME/.codex}/agents"
force="\${1:-}"
mkdir -p "$dest"
placed=0
for f in "$here"/agents/*.toml; do
  [ -e "$f" ] || continue
  name="$(basename "$f")"
  target="$dest/$name"
  if [ -e "$target" ] && cmp -s "$f" "$target"; then
    continue                      # identical — idempotent no-op
  fi
  if [ -e "$target" ] && [ "$force" != "--force" ]; then
    echo "skip (exists and differs; pass --force to overwrite): $name" >&2
    continue
  fi
  cp "$f" "$target"
  echo "installed: $name"
  placed=$((placed + 1))
done
echo "$placed agent(s) placed in $dest"
`

function readmeMd() {
  const addLine = MARKETPLACE_ADD_FROM_REPO
    ? '`codex plugin marketplace add galaykos/cc-marketplace`'
    : '`codex plugin marketplace add galaykos/cc-marketplace` (available once Codex self-serve publishing opens)'
  return `# Codex marketplace (generated)

This tree is generated one-way from the Claude Code plugins in \`plugins/\` by
\`scripts/gen-codex/\`. Do not hand-edit — run \`node scripts/gen-codex/gen.mjs\`;
\`scripts/validate-codex.sh\` enforces freshness in CI.

## Install (two parts)

1. **Skills + hooks** — add this repo as a Codex marketplace and install plugins:

   ${addLine}

   then browse/install with \`/plugins\`.

2. **Subagents** — Codex plugins cannot bundle subagents, so they install out-of-band.
   Clone this repo and run the generated installer:

   \`\`\`sh
   git clone https://github.com/galaykos/cc-marketplace
   cd cc-marketplace
   bash codex/install-agents.sh          # copies codex/agents/*.toml -> ~/.codex/agents
   \`\`\`

   Re-running is a no-op for unchanged agents; pass \`--force\` to overwrite local edits.

## Fidelity

Skills, hooks, and MCP port faithfully; commands become auto-trigger skills (no typed
\`/plugin:command\` verb); subagents install out-of-band; \`SessionEnd\` hooks, bundle
dependency fan-out, and interactive command branching are dropped. Per-plugin detail is
in each plugin's \`.codex-plugin/plugin.json\` \`fidelity\` block and the catalog.
`
}

register('installer', (plugin, ctx) => {
  if (plugin.name !== ctx.plugins[ctx.plugins.length - 1].name) return []
  return [
    { path: 'codex/install-agents.sh', content: INSTALL_SH, mode: 0o755 },
    { path: 'codex/README.md', content: readmeMd() },
  ]
})
